  ('aboriginal-a5729396-moex-00218', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-112-2d8844e1', 'sub-aboriginal-a5729396-01', NULL, 'single_choice', '陳小明為阿美族，民國112年大學畢業後準備參加公務人員特種考試原住民族三等考試，但他必須要 先取得原住民族語言能力認證才能參加考試，請問這是依據那一部法規範的規定？', '["原住民族基本法", "原住民族語言發展法", "原住民族語言能力認證辦法", "原住民族語言發展法施行細則"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:46+00:00", "source_pdf_sha1": "7225f4b2a66c", "answer_pdf_sha1": "f3e85653983c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0220", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00219', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-112-2d8844e1', 'sub-aboriginal-a5729396-01', NULL, 'single_choice', '依據原住民族教育法第19條，地方政府應設立任務編組性質之原住民族教育資源中心，有關原住民 族教育資源中心的設置規定與工作任務，何者錯誤？', '["辦理原住民族教育課程、教材與教學方法之研發及推廣", "協助各地方政府主管之學校，發展符合當地原住民族之民族教育課程規劃與評量方式", "負責各地方政府辦理原住民族教育統計與教育成果評量與管理", "原住民族教育資源中心所需經費，由中央教育主管機關及中央原住民族主管機關分別編列預算酌予 補助"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:46+00:00", "source_pdf_sha1": "7225f4b2a66c", "answer_pdf_sha1": "f3e85653983c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0220", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
