  ('aboriginal-a5729396-moex-00221', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-112-2d8844e1', 'sub-aboriginal-a5729396-01', NULL, 'single_choice', '依據原住民族語言發展法，政府捐助之原住民族電視及廣播機構，應製作原住民族語言節目及語言學 習課程，且其使用原住民族語言之時數，不得低於該機構總時數之多少比例？', '["百分之二", "百分之二十", "百分之三十", "百分之五十"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:46+00:00", "source_pdf_sha1": "7225f4b2a66c", "answer_pdf_sha1": "f3e85653983c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0220", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00222', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-112-2d8844e1', 'sub-aboriginal-a5729396-01', NULL, 'single_choice', '為實現歷史正義，促進原住民族語言之保存與發展，保障原住民族語言之使用及傳承，特制定原住民 族語言發展法。下列何者非本法用以推廣、促進原住民族語言保存與發展之項目？', '["原住民族地區之政府機關（構）、學校及公營事業機構，應設置地方通行語之標示", "設置專職語言推廣人員", "辦理原住民族語言能力認證", "規定原住民族重點學校應以原住民族語進行教學"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:46+00:00", "source_pdf_sha1": "7225f4b2a66c", "answer_pdf_sha1": "f3e85653983c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0220", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00223', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-112-2d8844e1', 'sub-aboriginal-a5729396-01', NULL, 'single_choice', '依據原住民族語言發展法，直轄市、縣（市）政府、原住民族地區及原住民人口多少人以上之非原住 民族地區之鄉（鎮、市、區）公所，應置專職原住民族語言推廣人員？', '["五百人", "一千人", "一千五百人", "二千五百人"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:46+00:00", "source_pdf_sha1": "7225f4b2a66c", "answer_pdf_sha1": "f3e85653983c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0220", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL)
